import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Defining a safe buffer size
        int bufferSize = Math.min(name.length(), 10);

        // Creating a buffer with proper length based on user input
        char[] buffer = new char[bufferSize];

        // Copying the user input into the buffer with proper length validation
        name.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

